#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> subsets(vector<int>& nums) {
        sort(nums.begin(), nums.end());
        vector<vector<int>> result;
        function<void(int, vector<int>)> backtrack = 
            [&backtrack, &result, &nums](int start, vector<int> path) {
                result.push_back(path);
                for (int i = start; i < nums.size(); i++) {
                    path.push_back(nums[i]);
                    backtrack(i + 1, path);
                    path.pop_back();
                }
            };
        backtrack(0, {});
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    vector<vector<int>> ans = sol.subsets(nums);
    for (const auto& subset : ans) {
        for (int i = 0; i < subset.size(); i++) {
            cout << subset[i] << (i == subset.size() - 1 ? "" : " ");
        }
        cout << "\n";
    }
    return 0;
}
